String cmd;
if (System.getProperty("os.name").toLowerCase().contains("win")) {
    cmd = "c:\\WINDOWS\\SYSTEM32\\cmd.exe /c dir ";
} else {
    cmd = "/bin/ls ";
}

Process process = Runtime.getRuntime().exec(cmd + value);
process.waitFor();

fixes.replacement:
Process process;
if (System.getProperty("os.name").toLowerCase().contains("win")) {
    process = new ProcessBuilder("cmd.exe", "/c", "dir", value).start();
} else {
    process = new ProcessBuilder("/bin/ls", value).start();
}
process.waitFor();
